const express = require('express');
const axios = require('axios');
const morgan = require('morgan');

const app = express();

app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true }));

app.use((req, res, next) => {
  const apiKey = req.query.api_key || '';
  console.log(`[DEBUG] ${new Date().toISOString()} ${req.method} ${req.originalUrl} api_key=${apiKey}`);
  next();
});

app.use(
  morgan(':method :url :status :res[content-length] - :response-time ms')
);

const services = {
  users: 'http://localhost:3001',
  orders: 'http://localhost:3002',
  payments: 'http://localhost:3003'
};

app.use('/api/:service', async (req, res) => {
  const { service } = req.params;
  const targetBase = services[service];

  if (!targetBase) {
    return res.status(404).json({ error: 'Unknown service' });
  }

  const apiKey = req.query.api_key;
  if (!apiKey) {
    return res.status(401).json({ error: 'Missing api_key' });
  }

  const forwardPath = req.originalUrl.replace(`/api/${service}`, '');
  const targetUrl = `${targetBase}${forwardPath}`;

  try {
    const headers = { ...req.headers, 'x-api-key': apiKey };
    delete headers.host;

    const response = await axios({
      method: req.method,
      url: targetUrl,
      headers,
      data: req.body,
      validateStatus: () => true
    });

    Object.entries(response.headers || {}).forEach(([key, value]) => {
      if (key.toLowerCase() === 'transfer-encoding') return;
      res.setHeader(key, value);
    });

    res.status(response.status).send(response.data);
  } catch (error) {
    res.status(502).json({
      error: 'Bad gateway',
      message: error.message
    });
  }
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`API Gateway listening on port ${PORT}`);
});